// 对当前文档进行语义检查，添加批注
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
var content = "";
for (var i = 1; i <= paragraphs.Count; i++) {
    content += paragraphs.Item(i).Range.Text + "\n";
}

// 调用LLM进行语义分析
var result = chat({
    system: "你是一个技术文档语义检查专家。请分析以下技术文档内容，检查术语一致性、模糊引用、图表引用完整性、繁体字等问题。输出JSON数组格式，每个问题包含rule、name、location、original、suggestion字段。无问题输出[]。",
    user: "文档内容：\n" + content.substring(0, 15000) // 限制长度
});

return result;
